const tsvText = $input.first().json.data || $input.first().json.body || '';
const raw = typeof tsvText === 'string' ? tsvText : String(tsvText);
const lines = raw.split('\n').filter(l => l.trim().length > 0);

const map = {};

for (const line of lines) {
  const col = line.split('\t');
  if (col.length < 13) continue;

  const date = col[0];
  const adId = col[5];
  const method = String(col[9]).trim();
  const convType = String(col[10]).trim();
  const convCount = Number(col[11]) || 0;
  const convSales = Number(col[12]) || 0;

  if (!map[adId]) {
    map[adId] = {
      수집일: date.replace(/^(\d{4})(\d{2})(\d{2})$/, '$1-$2-$3'),
      상품ID: adId,
      구매전환수: 0,
      구매전환매출: 0,
      직접구매전환수: 0,
      직접구매전환매출: 0,
      간접구매전환수: 0,
      간접구매전환매출: 0,
      장바구니수: 0,
      장바구니추정매출: 0,
      기타전환수: 0,
    };
  }

  const row = map[adId];

  if (convType === 'purchase') {
    row.구매전환수 += convCount;
    row.구매전환매출 += convSales;
    if (method === '1') {
      row.직접구매전환수 += convCount;
      row.직접구매전환매출 += convSales;
    } else if (method === '2') {
      row.간접구매전환수 += convCount;
      row.간접구매전환매출 += convSales;
    }
  } else if (convType === 'add_to_cart') {
    row.장바구니수 += convCount;
    row.장바구니추정매출 += convSales;
  } else {
    row.기타전환수 += convCount;
  }
}

return Object.values(map).map(v => ({ json: v }));

// 파이프라인 출력 직접 참조
const adRows = $('시트_저장_Phase2').all();
const convRows = $('시트_저장_Conv').all();

// 전환 데이터를 상품ID 기준으로 집계
const convMap = {};
for (const item of convRows) {
  const r = item.json;
  const key = r['상품ID'] || '';
  if (!key) continue;
  if (!convMap[key]) convMap[key] = { 구매전환수: 0, 구매전환매출: 0, 장바구니수: 0 };
  convMap[key].구매전환수 += parseInt(r['구매전환수']) || 0;
  convMap[key].구매전환매출 += parseFloat(r['구매전환매출']) || 0;
  convMap[key].장바구니수 += parseInt(r['장바구니수']) || 0;
}

// AD + Conv 조인
const merged = adRows.map(item => {
  const r = item.json;
  const adId = r['상품명'] || '';
  const c = convMap[adId] || { 구매전환수: 0, 구매전환매출: 0, 장바구니수: 0 };
  const cost = parseFloat(r['비용']) || 0;
  const roas = cost > 0 ? (c.구매전환매출 / cost) * 100 : 0;
  // 상품명(매핑) 우선, 없으면 상품ID
  const displayName = r['상품명(매핑)'] || r['K'] || adId;

  return {
    json: {
      수집일: r['수집일'],
      캠페인: r['캠페인'],
      광고그룹: r['광고그룹'],
      상품명: displayName,
      상품ID: adId,
      노출: parseInt(r['노출']) || 0,
      클릭: parseInt(r['클릭']) || 0,
      CTR: parseFloat(r['CTR']) || 0,
      비용: cost,
      전환수_구매: c.구매전환수,
      전환매출_구매: c.구매전환매출,
      전환수_장바구니: c.장바구니수,
      실_ROAS: Number(roas.toFixed(1)),
      평균노출순위: parseFloat(r['평균노출순위']) || 0,
    }
  };
});

// 캠페인별 집계
const campMap = {};
for (const item of merged) {
  const r = item.json;
  const camp = r.캠페인 || '미분류';
  if (!campMap[camp]) campMap[camp] = { 소재수:0, 노출:0, 클릭:0, 비용:0, 매출:0 };
  campMap[camp].소재수++;
  campMap[camp].노출 += r.노출;
  campMap[camp].클릭 += r.클릭;
  campMap[camp].비용 += r.비용;
  campMap[camp].매출 += r.전환매출_구매;
}
const campSummary = Object.entries(campMap).map(([name, d]) => ({
  캠페인: name, ...d,
  CTR: d.노출 > 0 ? Number(((d.클릭/d.노출)*100).toFixed(2)) : 0,
  ROAS: d.비용 > 0 ? Number(((d.매출/d.비용)*100).toFixed(1)) : 0,
})).sort((a,b) => b.비용 - a.비용);

// 전체 요약
const total = merged.reduce((acc, item) => {
  const r = item.json;
  acc.노출 += r.노출; acc.클릭 += r.클릭; acc.비용 += r.비용;
  acc.매출 += r.전환매출_구매; acc.전환수 += r.전환수_구매;
  return acc;
}, {노출:0, 클릭:0, 비용:0, 매출:0, 전환수:0});
total.CTR = total.노출 > 0 ? Number(((total.클릭/total.노출)*100).toFixed(2)) : 0;
total.실_ROAS = total.비용 > 0 ? Number(((total.매출/total.비용)*100).toFixed(1)) : 0;

// 첫 아이템에 메타데이터 부착
merged[0].json._meta = {
  총_상품수: merged.length,
  총_노출: total.노출,
  총_클릭: total.클릭,
  총_CTR: total.CTR,
  총_비용: total.비용,
  총_매출: total.매출,
  총_전환수: total.전환수,
  전체_실_ROAS: total.실_ROAS + '%',
  캠페인별: campSummary,
  수집일: merged[0]?.json?.수집일 || '',
};

return merged;

const rows = $('데이터_합산').all();

const 이상_항목 = [];
const 정상_상품 = [];
let 총비용 = 0;
let 총매출 = 0;

for (const item of rows) {
  const r = item.json;
  총비용 += r.비용;
  총매출 += r.전환매출_구매;

  const alerts = [];

  // D-01: 실_ROAS 전일대비 -20% 이상 하락 (전일 데이터 있는 경우만)
  if (r.전일_비용 !== null && r.전일_비용 > 0 && r.비용 > 0) {
    // 전일 ROAS 계산은 전일 전환 데이터가 없으므로 skip (Phase 3.1에서 보완)
  }

  // D-02: CTR 전일대비 -40% 이상 하락
  if (r.전일_CTR !== null && r.전일_CTR > 0) {
    const ctrDrop = ((r.CTR - r.전일_CTR) / r.전일_CTR) * 100;
    if (ctrDrop <= -40) {
      alerts.push({
        규칙: 'D-02', 심각도: '상',
        현재값: `CTR ${r.CTR}%`, 전일값: `CTR ${r.전일_CTR}%`,
        변동: `${ctrDrop.toFixed(1)}%`, 설명: `CTR 전일대비 ${Math.abs(ctrDrop).toFixed(1)}% 하락`
      });
    }
  }

  // D-03: 평균노출순위 전일대비 5단계+ 하락
  if (r.전일_평균노출순위 !== null && r.전일_평균노출순위 > 0) {
    const rankDrop = r.평균노출순위 - r.전일_평균노출순위;
    if (rankDrop >= 5) {
      alerts.push({
        규칙: 'D-03', 심각도: '중',
        현재값: `순위 ${r.평균노출순위}`, 전일값: `순위 ${r.전일_평균노출순위}`,
        변동: `+${rankDrop.toFixed(1)}단계`, 설명: `평균노출순위 ${rankDrop.toFixed(1)}단계 하락`
      });
    }
  }

  // D-04: 노출 > 0 & 클릭 = 0
  if (r.노출 > 100 && r.클릭 === 0) {
    alerts.push({
      규칙: 'D-04', 심각도: '중',
      현재값: `노출 ${r.노출} / 클릭 0`, 전일값: '-',
      변동: '-', 설명: `노출 ${r.노출}회인데 클릭 0건`
    });
  }

  // 추가: 비용 > 10,000 & 전환수_구매 = 0
  if (r.비용 > 10000 && r.전환수_구매 === 0) {
    alerts.push({
      규칙: 'COST-NO-CONV', 심각도: '상',
